mapper.select:
select t1.*
   , t2.orgn_nm
from esg.tb_emergency_response_training t1
left join esg.tb_orgn_info t2
   on t1.comp_id = t2.comp_id
   and t1.orgn_id = t2.orgn_id
where t1.write_year = #{writeYear}
   and t1.doc_type = #{docType}
   and t1.doc_no = #{docNo}
   and t1.comp_id = #{compId}

select t1.*
from esg.tb_emergency_response_training_scenario t1
where t1.write_year = #{writeYear}
   and t1.doc_type = #{docType}
   and t1.doc_no = #{docNo}
   and t1.comp_id = #{compId}
order by doc_seq asc

mapper.update:
update esg.tb_emergency_response_training set
    training_nm = #{trainingNm},
    training_location = #{trainingLocation},
    training_content = #{trainingContent},
    anticipated_damage = #{anticipatedDamage},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and comp_id = #{compId};

update esg.tb_emergency_response_training set
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and comp_id = #{compId};

update esg.tb_emergency_response_training_scenario set
    target_time = #{targetTime},
    situation = #{situation},
    performer = #{performer},
    method_action = #{methodAction},
    remark = #{remark},
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and doc_seq = #{docSeq}
    and comp_id = #{compId}

mapper.delete:
delete from esg.tb_emergency_response_training_scenario
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and doc_seq = #{docSeq}
    and comp_id = #{compId}
